```typescript
import { setup, assign, fromPromise } from 'xstate';

type Message = {
  id: string;
  body: string;
  status: 'pending' | 'sent' | 'failed';
};

type Ctx = { messages: Message[]; draft: string };

type Ev =
  | { type: 'DRAFT.CHANGE'; value: string }
  | { type: 'SEND' }
  | { type: 'RETRY'; id: string };

export const chatMachine = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev
  },
  actors: {
    sendMessage: fromPromise(
      async ({ input }: { input: { id: string; body: string } }) => {
        await new Promise((r) => setTimeout(r, 200));
        if (input.body.length === 0) throw new Error('empty');
        return { id: input.id };
      }
    )
  },
  actions: {
    markPending: assign({
      messages: ({ context }) => {
        const id = String(Date.now());
        const msg: Message = { id, body: context.draft, status: 'pending' };
        return context.messages.concat(msg);
      },
      draft: ''
    })
  }
}).createMachine({
  id: 'chat',
  initial: 'idle',
  context: { messages: [], draft: '' },
  states: {
    idle: {
      on: {
        'DRAFT.CHANGE': {
          actions: assign({ draft: ({ event }) => event.value })
        },
        SEND: { target: 'sending', guard: ({ context }) => context.draft.length > 0, actions: 'markPending' },
        RETRY: 'sending'
      }
    },
    sending: {
      invoke: {
        src: 'sendMessage',
        input: ({ context }) => {
          const last = context.messages[context.messages.length - 1];
          return { id: last.id, body: last.body };
        },
        onDone: {
          target: 'idle',
          actions: assign({
            messages: ({ context, event }) =>
              context.messages.map((m) => (m.id === event.output.id ? { ...m, status: 'sent' as const } : m))
          })
        },
        onError: {
          target: 'idle',
          actions: assign({
            messages: ({ context }) =>
              context.messages.map((m, i, arr) => (i === arr.length - 1 ? { ...m, status: 'failed' as const } : m))
          })
        }
      }
    }
  }
});
```

Use a named `after` delay so each `TYPING` event retargets the same state and resets the timer.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { userId: string | null };
type Ev = { type: 'TYPING'; userId: string } | { type: 'STOP' };

export const typingIndicator = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { IDLE: 3000 }
}).createMachine({
  id: 'typing',
  initial: 'idle',
  context: { userId: null },
  states: {
    idle: {
      on: {
        TYPING: {
          target: 'active',
          actions: assign({ userId: ({ event }) => event.userId })
        }
      }
    },
    active: {
      on: {
        TYPING: {
          target: 'active',
          reenter: true,
          actions: assign({ userId: ({ event }) => event.userId })
        },
        STOP: 'idle'
      },
      after: {
        IDLE: { target: 'idle', actions: assign({ userId: null }) }
      }
    }
  }
});
```

A receive pipeline stays in an `open` state and handles `MESSAGE.RECEIVED` events by appending the payload to a typed `messages` array. We declare the append as a named action so the transition body stays string-referenced.

```typescript
import { setup, assign } from 'xstate';

type Msg = { id: string; from: string; body: string; ts: number };
type Ctx = { messages: Msg[] };
type Ev =
  | { type: 'MESSAGE.RECEIVED'; message: Msg }
  | { type: 'CLEAR' };

export const inboxMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    appendMessage: assign({
      messages: ({ context, event }) => {
        if (event.type !== 'MESSAGE.RECEIVED') return context.messages;
        return context.messages.concat(event.message);
      }
    }),
    clear: assign({ messages: () => [] as Msg[] })
  }
}).createMachine({
  id: 'inbox',
  initial: 'open',
  context: { messages: [] },
  states: {
    open: {
      on: {
        'MESSAGE.RECEIVED': { actions: 'appendMessage' },
        CLEAR: { actions: 'clear' }
      }
    }
  }
});
```

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Status = 'pending' | 'sent' | 'failed';
type Msg = { id: string; body: string; status: Status };
type Ctx = { queue: Msg[] };
type Ev =
  | { type: 'ENQUEUE'; body: string }
  | { type: 'RETRY_LAST' };

export const outboxMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    transmit: fromPromise(
      async ({ input }: { input: { id: string; body: string } }) => {
        await new Promise((r) => setTimeout(r, 100));
        if (input.body === 'boom') throw new Error('server');
        return { id: input.id };
      }
    )
  },
  actions: {
    enqueue: assign({
      queue: ({ context, event }) => {
        if (event.type !== 'ENQUEUE') return context.queue;
        return context.queue.concat({ id: String(Date.now()), body: event.body, status: 'pending' });
      }
    }),
    markSent: assign({
      queue: ({ context }) =>
        context.queue.map((m) => (m.status === 'pending' ? { ...m, status: 'sent' as const } : m))
    })
  }
}).createMachine({
  id: 'outbox',
  initial: 'idle',
  context: { queue: [] },
  states: {
    idle: {
      on: {
        ENQUEUE: { target: 'sending', actions: 'enqueue' },
        RETRY_LAST: {
          target: 'sending',
          guard: ({ context }) => context.queue.some((m) => m.status === 'failed'),
          actions: assign({
            queue: ({ context }) =>
              context.queue.map((m) => (m.status === 'failed' ? { ...m, status: 'pending' as const } : m))
          })
        }
      }
    },
    sending: {
      invoke: {
        id: 'tx',
        src: 'transmit',
        input: ({ context }) => {
          const p = context.queue.find((m) => m.status === 'pending');
          return { id: p?.id ?? '', body: p?.body ?? '' };
        },
        onDone: { target: 'idle', actions: 'markSent' },
        onError: {
          target: 'idle',
          actions: assign({
            queue: ({ context }) =>
              context.queue.map((m) => (m.status === 'pending' ? { ...m, status: 'failed' as const } : m))
          })
        }
      }
    }
  }
});
```

