import { setup, assign, fromPromise } from 'xstate';

type Status = 'pending' | 'sent' | 'failed';
type Msg = { id: string; body: string; status: Status; from: 'me' | 'peer' };
type Ctx = { thread: Msg[] };
type Ev =
  | { type: 'SEND'; body: string }
  | { type: 'MESSAGE.RECEIVED'; id: string; body: string };

export const threadMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    post: fromPromise(
      async ({ input }: { input: { id: string } }) => {
        await new Promise((r) => setTimeout(r, 150));
        return { id: input.id };
      }
    )
  }
}).createMachine({
  id: 'thread',
  initial: 'open',
  context: { thread: [] },
  states: {
    open: {
      on: {
        'MESSAGE.RECEIVED': {
          actions: assign({
            thread: ({ context, event }) =>
              context.thread.concat({ id: event.id, body: event.body, status: 'sent', from: 'peer' })
          })
        },
        SEND: {
          target: 'sending',
          actions: assign({
            thread: ({ context, event }) =>
              context.thread.concat({
                id: String(Date.now()),
                body: event.body,
                status: 'pending',
                from: 'me'
              })
          })
        }
      }
    },
    sending: {
      invoke: {
        src: 'post',
        input: ({ context }) => {
          const pending = context.thread.filter((m) => m.status === 'pending' && m.from === 'me');
          const p = pending[pending.length - 1];
          return { id: p?.id ?? '' };
        },
        onDone: {
          target: 'open',
          actions: assign({
            thread: ({ context, event }) =>
              context.thread.map((m) => (m.id === event.output.id ? { ...m, status: 'sent' as const } : m))
          })
        },
        onError: { target: 'open' }
      }
    }
  }
});
