type Ctx = { query: string; results: string[]; error: string | null };
type Ev = { type: 'CHANGE'; value: string } | { type: 'CLEAR' };

export const searchMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { DEBOUNCE: 300 },
