    search: fromPromise(
      async ({ input }: { input: { q: string } }): Promise<string[]> => {
        await new Promise((r) => setTimeout(r, 120));
        if (input.q === 'x') throw new Error('bad query');
        return input.q.length === 0 ? [] : [`${input.q}-1`, `${input.q}-2`];
      }
    )
  }
