  id: 'search',
  initial: 'idle',
  context: { query: '', results: [], error: null },
  states: {
    idle: {
      on: {
        CHANGE: { target: 'debouncing', actions: assign({ query: ({ event }) => event.value }) }
      }
    },
    debouncing: {
      on: {
        CHANGE: { target: 'debouncing', reenter: true, actions: assign({ query: ({ event }) => event.value }) },
        CLEAR: { target: 'idle', actions: assign({ query: '', results: [] }) }
      },
      after: { DEBOUNCE: 'loading' }
    },
    loading: {
      on: {
        CHANGE: { target: 'debouncing', actions: assign({ query: ({ event }) => event.value }) }
      },
      invoke: {
        src: 'search',
        input: ({ context }) => ({ q: context.query }),
        onDone: [
          { target: 'empty', guard: ({ event }) => event.output.length === 0 },
          { target: 'results', actions: assign({ results: ({ event }) => event.output }) }
        ],
        onError: {
          target: 'error',
          actions: assign({ error: ({ event }) => String(event.error) })
        }
      }
    },
    empty: { on: { CHANGE: { target: 'debouncing', actions: assign({ query: ({ event }) => event.value }) } } },
    results: { on: { CHANGE: { target: 'debouncing', actions: assign({ query: ({ event }) => event.value }) } } },
