type Ctx = { q: string; hits: string[] };
type Ev = { type: 'CHANGE'; value: string };

export const liveSearch = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  delays: { DEBOUNCE: 250 },
  actors: {
    search: fromPromise(
      async ({ input }: { input: { q: string } }): Promise<string[]> => {
        await new Promise((r) => setTimeout(r, 400));
        return [input.q];
      }
    )
  }
}).createMachine({
  id: 'live',
  initial: 'idle',
  context: { q: '', hits: [] },
  states: {
    idle: { on: { CHANGE: { target: 'debouncing', actions: assign({ q: ({ event }) => event.value }) } } },
    debouncing: {
      on: { CHANGE: { target: 'debouncing', reenter: true, actions: assign({ q: ({ event }) => event.value }) } },
      after: { DEBOUNCE: 'loading' }
    },
    loading: {
      on: { CHANGE: { target: 'debouncing', actions: assign({ q: ({ event }) => event.value }) } },
      invoke: {
        src: 'search',
        input: ({ context }) => ({ q: context.q }),
