import { setup, assign, fromCallback } from 'xstate';

type Ctx = { url: string; attempts: number; lastError: string | null };
type Ev =
  | { type: 'OPEN' }
  | { type: 'CLOSE' }
  | { type: 'ERROR'; message: string }
  | { type: 'USER.DISCONNECT' };

export const wsMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev, input: {} as { url: string } },
  actors: {
    socket: fromCallback(({ sendBack }) => {
      const id = setTimeout(() => sendBack({ type: 'OPEN' }), 50);
      return () => clearTimeout(id);
    })
  },
  delays: {
    BACKOFF: ({ context }) => Math.min(30000, 500 * 2 ** context.attempts)
  }
}).createMachine({
  id: 'ws',
  initial: 'connecting',
  context: ({ input }) => ({ url: input.url, attempts: 0, lastError: null }),
  states: {
    connecting: {
      invoke: { src: 'socket', input: ({ context }) => ({ url: context.url }) },
      on: {
        OPEN: { target: 'open', actions: assign({ attempts: 0, lastError: null }) },
        ERROR: { target: 'backoff', actions: assign({ lastError: ({ event }) => event.message }) }
      }
    },
    open: {
      invoke: { src: 'socket', input: ({ context }) => ({ url: context.url }) },
      on: {
        CLOSE: 'backoff',
        ERROR: { target: 'backoff', actions: assign({ lastError: ({ event }) => event.message }) },
        'USER.DISCONNECT': 'closed'
      }
    },
    backoff: {
      entry: assign({ attempts: ({ context }) => context.attempts + 1 }),
      after: { BACKOFF: 'connecting' },
      on: { 'USER.DISCONNECT': 'closed' }
    },
    closed: { type: 'final' }
  }
});
```

Wrap the emitter in `fromCallback`, forward lifecycle events via `sendBack`, accept outgoing frames through `receive`, and return a cleanup that tears down the subscription.

```typescript
import { setup, fromCallback } from 'xstate';

type ParentEv =
  | { type: 'WS.OPEN' }
  | { type: 'WS.MESSAGE'; data: string }
  | { type: 'WS.CLOSE' };

type ChildEv = { type: 'SEND'; data: string };

export const m = setup({
  types: {
    events: {} as ParentEv
  },
  actors: {
    wsActor: fromCallback(({ sendBack, receive }) => {
      const openId = setTimeout(() => sendBack({ type: 'WS.OPEN' }), 10);
      receive((ev) => {
        const child = ev as ChildEv;
        if (child.type === 'SEND') {
          sendBack({ type: 'WS.MESSAGE', data: child.data });
        }
      });
      return () => clearTimeout(openId);
    })
  }
}).createMachine({
  id: 'socket',
  invoke: { src: 'wsActor', input: { url: 'wss://example' } },
  on: {
    'WS.OPEN': {},
    'WS.MESSAGE': {},
    'WS.CLOSE': {}
  }
});
```

