  types: { context: {} as Ctx, events: {} as Ev },
  actors: {
    send: fromPromise(async ({ input }: { input: { id: string } }) => {
      if (input.id.endsWith('X')) throw new Error('fail');
      return input.id;
    })
  },
  guards: {
    hasOp: ({ context }) => context.outbox.length > 0,
    canRetry: ({ context }) => (context.outbox[0]?.attempts ?? 0) < 3
  }
}).createMachine({
  id: 'reconcile',
  initial: 'idle',
  context: { outbox: [], dead: [] },
  states: {
    idle: { on: { DRAIN: { target: 'sending', guard: 'hasOp' } } },
    sending: {
      invoke: {
        src: 'send',
        input: ({ context }) => ({ id: context.outbox[0]?.id ?? '' }),
        onDone: {
          target: 'idle',
          actions: assign({ outbox: ({ context }) => context.outbox.slice(1) })
        },
        onError: [
          {
            target: 'sending',
            guard: 'canRetry',
            reenter: true,
            actions: assign({
              outbox: ({ context }) =>
                context.outbox.map((op, i) => (i === 0 ? { ...op, attempts: op.attempts + 1 } : op))
            })
          },
          {
            target: 'idle',
            actions: assign({
              dead: ({ context }) => context.dead.concat(context.outbox[0]!),
              outbox: ({ context }) => context.outbox.slice(1)
            })
          }
        ]
      }
    }
  }
});
