import { setup, assign, enqueueActions } from 'xstate';

type Ctx = { i: number; total: number };
type Ev = { type: 'ARROW_LEFT' } | { type: 'ARROW_RIGHT' };

export const keyboardSlider = setup({
  types: { context: {} as Ctx, events: {} as Ev, input: {} as { total: number } },
  guards: {
    canNext: ({ context }) => context.i + 1 < context.total,
    canPrev: ({ context }) => context.i > 0
  },
  actions: {
    step: enqueueActions(({ enqueue, event, check }) => {
      if (event.type === 'ARROW_RIGHT' && check('canNext')) {
        enqueue.assign({ i: ({ context }) => context.i + 1 });
      }
      if (event.type === 'ARROW_LEFT' && check('canPrev')) {
        enqueue.assign({ i: ({ context }) => context.i - 1 });
      }
    })
  }
}).createMachine({
  id: 'kbd-slider',
  context: ({ input }) => ({ i: 0, total: input.total }),
  on: {
    ARROW_LEFT: { actions: 'step' },
    ARROW_RIGHT: { actions: 'step' }
  }
});
